# Simplest Claude Integration for Next.js

Here's the fastest path to add AI features with real-time responses:

## 1. **API Route with Streaming**

Create a Next.js API route that streams Claude responses directly to the client:

```typescript
// app/api/chat/route.ts
import Anthropic from "@anthropic-ai/sdk";

const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

export async function POST(req: Request) {
  const { message, context } = await req.json();

  const stream = await anthropic.messages.stream({
    model: "claude-opus-4-6", // or claude-sonnet-4-6 for faster, cheaper
    max_tokens: 1024,
    system: `You are a helpful assistant analyzing user data. 
Context: ${context}`,
    messages: [
      {
        role: "user",
        content: message,
      },
    ],
  });

  // Convert to ReadableStream for Next.js
  return stream.toResponse();
}
```

## 2. **Client-Side Streaming**

Use React hooks to consume the stream:

```typescript
// app/components/ChatInterface.tsx
"use client";

import { useState } from "react";

export function ChatInterface({ userContext }: { userContext: string }) {
  const [input, setInput] = useState("");
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setResponse("");

    const reader = (
      await fetch("/api/chat", {
        method: "POST",
        body: JSON.stringify({
          message: input,
          context: userContext,
        }),
      })
    ).body?.getReader();

    if (!reader) return;

    const decoder = new TextDecoder();
    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      // Parse SSE format
      const chunk = decoder.decode(value);
      const lines = chunk.split("\n");

      for (const line of lines) {
        if (line.startsWith("data: ")) {
          const data = JSON.parse(line.slice(6));
          if (
            data.type === "content_block_delta" &&
            data.delta.type === "text_delta"
          ) {
            setResponse((prev) => prev + data.delta.text);
          }
        }
      }
    }

    setLoading(false);
  };

  return (
    <div>
      <form onSubmit={handleSubmit}>
        <input
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Ask a question about your data..."
          disabled={loading}
        />
        <button type="submit" disabled={loading}>
          {loading ? "Thinking..." : "Send"}
        </button>
      </form>
      <div className="response">{response}</div>
    </div>
  );
}
```

